import { initializeApp } from 'firebase/app';
import { getFirestore , enableIndexedDbPersistence, collection, doc, getDocs, writeBatch } from 'firebase/firestore';
import  { getAuth, signInAnonymously, onAuthStateChanged } from 'firebase/auth';
import type { User  } from 'firebase/auth';

// --- ACTION REQUIRED ---
// This configuration is now correctly placed here.
const  firebaseConfig = {
  apiKey: "AIzaSyAX5FrYaMSBy-R-DfZV 6mbh2izdUWch8iQ",
  authDomain: "restaurant-pos-1cdf8 .firebaseapp.com",
  projectId: "restaurant-pos-1cdf8",
  storageBucket:  "restaurant-pos-1cdf8.firebasestorage.app",
  messagingSenderId: "1 049883141132",
  appId: "1:104 9883141132:web:1a8e0ade03596 2e154ba29"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
export const db = getFirestore(app);
export const auth = getAuth(app);

// Enable offline persistence
enableIndexedDbPersistence(db)
  .catch((err) => {
    if (err.code == 'failed-precondition') {
      // Multiple tabs open, persistence can only be enabled
      // in one tab at a time.
      console.log('Persistence failed: Multiple tabs open.');
    } else if (err.code == 'unimplemented') {
      // The current browser does not support all of the
      // features required to enable persistence
      console.log('Persistence not supported.');
    }
  });

// Authentication
export async function ensureAuthenticated(): Promise<User | null> {
  return new Promise((resolve, reject) => {
    onAuthStateChanged(auth, (user) => {
      if (user) {
        // User is signed in.
        resolve(user);
      } else {
        // User is signed out.
        signInAnonymously(auth)
          .then((userCredential) => {
            // Signed in..
            const user = userCredential.user;
            resolve(user);
          })
          .catch((error) => {
            console.error('Anonymous sign-in error:', error);
            reject(error);
          });
      }
    });
  });
}

//Constants
export const RESTAURANT_ID = "main"; // Replace with your restaurant ID

// Clear all data (For testing purposes and potential reset functionality)
export async function clearAllData() {
  const batch = writeBatch(db);
  // Delete all items from each collection
  const collections = ['items', 'receipts', 'settings', 'tabs', 'categories'];
  for (const col of collections) {
    const collectionRef = collection(db, col);
    const querySnapshot = await getDocs(collectionRef);
    querySnapshot.forEach((doc) => {
      batch.delete(doc.ref);
    });
  }
  await batch.commit();
  console.log('All data cleared successfully.');
}
